import type { PublicCard } from '../../../types';

export const satMathPatternsCardsPart1: PublicCard[] = [
  { id: 'dc-sat-mathp-0001', deck_id: 'deck-sat-math-patterns', front: 'When you see "the system of equations has no solution," what pattern should you recognize?', back: 'Pattern: The two equations represent parallel lines (same slope, different intercepts). Strategy: Rewrite both equations in slope-intercept form and set the slopes equal while ensuring the intercepts differ. If there is a constant to solve for, find the value that makes slopes equal. Example: 3x + ky = 10 and 6x + 4y = 5 → k must make 3/k = 6/4, so k = 2.', sort_order: 1 },
  { id: 'dc-sat-mathp-0002', deck_id: 'deck-sat-math-patterns', front: 'When you see "infinitely many solutions," what pattern should you recognize?', back: 'Pattern: Both equations are the same line in disguise. Strategy: Multiply one equation by a constant and see if you can make it identical to the other. If there is an unknown constant, find the value that makes all three ratios (a₁/a₂ = b₁/b₂ = c₁/c₂) equal. Example: 2x + 3y = 6 and 4x + 6y = 12 are the same line (multiply the first by 2).', sort_order: 2 },
  { id: 'dc-sat-mathp-0003', deck_id: 'deck-sat-math-patterns', front: 'When you see an equation like x⁴ − 5x² + 4 = 0, what pattern should you recognize?', back: 'Pattern: Disguised quadratic (also called "quadratic in form"). Strategy: Substitute u = x², so the equation becomes u² − 5u + 4 = 0. Factor: (u − 1)(u − 4) = 0, so u = 1 or u = 4, meaning x = ±1 or x = ±2. Always remember to substitute back and check all solutions.', sort_order: 3 },
  { id: 'dc-sat-mathp-0004', deck_id: 'deck-sat-math-patterns', front: 'When you see x² + bx and need to complete the square, what is the shortcut?', back: 'Pattern: Completing the square. Strategy: Take half of b, square it, and add/subtract that value. x² + bx = (x + b/2)² − (b/2)². Example: x² + 6x = (x + 3)² − 9. This converts to vertex form instantly. SAT Tip: The vertex of y = x² + bx + c is at x = −b/2, and the minimum/maximum value is c − b²/4.', sort_order: 4 },
  { id: 'dc-sat-mathp-0005', deck_id: 'deck-sat-math-patterns', front: 'When you see |ax + b| = c, what trap should you watch for?', back: 'Pattern: Absolute value equation. Strategy: Split into two cases: ax + b = c and ax + b = −c. TRAP: If c is negative, there is NO solution (absolute value can never equal a negative number). Also check that both solutions satisfy the original equation. Example: |2x − 3| = 7 → 2x − 3 = 7 or 2x − 3 = −7 → x = 5 or x = −2.', sort_order: 5 },
  { id: 'dc-sat-mathp-0006', deck_id: 'deck-sat-math-patterns', front: 'When you see |ax + b| < c or |ax + b| > c, how do you handle these?', back: 'Pattern: Absolute value inequalities. Strategy: For |expression| < c, rewrite as −c < expression < c (an "and" compound inequality). For |expression| > c, rewrite as expression > c OR expression < −c. Example: |x − 4| < 3 becomes 1 < x < 7. TRAP: Do not forget to flip the inequality when multiplying or dividing by a negative.', sort_order: 6 },
  { id: 'dc-sat-mathp-0007', deck_id: 'deck-sat-math-patterns', front: 'When you see expressions like 2³ˣ⁺¹ = 8², what exponent manipulation pattern should you use?', back: 'Pattern: Same-base exponent matching. Strategy: Rewrite both sides with the same base, then set the exponents equal. Since 8 = 2³, rewrite as 2³ˣ⁺¹ = 2⁶. So 3x + 1 = 6, giving x = 5/3. SAT Tip: Common bases to look for are 2, 3, 5, and 10. Know that 4 = 2², 8 = 2³, 16 = 2⁴, 27 = 3³, 25 = 5².', sort_order: 7 },
  { id: 'dc-sat-mathp-0008', deck_id: 'deck-sat-math-patterns', front: 'When a system of equations asks for a combined expression like 3x + 2y instead of individual values, what shortcut exists?', back: 'Pattern: Combined expression shortcut. Strategy: Instead of solving for x and y individually, try adding or subtracting the equations (or multiplying by constants first) to directly produce the expression asked for. Example: If x + y = 7 and 2x + y = 10, subtracting gives x = 3, but if asked for 3x + 2y, add the equations to get 3x + 2y = 17 directly.', sort_order: 8 },
  { id: 'dc-sat-mathp-0009', deck_id: 'deck-sat-math-patterns', front: 'When you see a quadratic equation and the question asks for the sum or product of the solutions, what is the fast approach?', back: 'Pattern: Vieta\'s formulas. For ax² + bx + c = 0, the sum of roots = −b/a and the product of roots = c/a. No need to solve the equation. Example: For 2x² − 7x + 3 = 0, sum of roots = 7/2 and product of roots = 3/2. SAT Tip: This saves significant time on "sum of all solutions" questions.', sort_order: 9 },
  { id: 'dc-sat-mathp-0010', deck_id: 'deck-sat-math-patterns', front: 'When you see a rational equation like (x² − 4)/(x − 2) = 5, what should you watch for?', back: 'Pattern: Factorable numerator with a restriction. Strategy: Factor the numerator: (x + 2)(x − 2)/(x − 2) = 5. Cancel to get x + 2 = 5, so x = 3. TRAP: Always check that your solution does not make the original denominator zero. Here x = 2 would be excluded, but x = 3 is valid. The SAT tests whether you notice the domain restriction.', sort_order: 10 },
  { id: 'dc-sat-mathp-0011', deck_id: 'deck-sat-math-patterns', front: 'When you see an equation with a variable under a square root, what is the key strategy?', back: 'Pattern: Radical equation. Strategy: Isolate the radical on one side, then square both sides to eliminate it. CRITICAL: Always check your solution in the original equation because squaring can introduce extraneous solutions. Example: √(x + 3) = x − 1 → x + 3 = x² − 2x + 1 → x² − 3x − 2 = 0. Check both solutions — only keep the ones where both sides are non-negative.', sort_order: 11 },
  { id: 'dc-sat-mathp-0012', deck_id: 'deck-sat-math-patterns', front: 'When a quadratic is given as y = a(x − h)² + k, what can you instantly determine?', back: 'Pattern: Vertex form recognition. The vertex is (h, k). If a > 0, the parabola opens up and k is the minimum value. If a < 0, it opens down and k is the maximum. The axis of symmetry is x = h. SAT Tip: If the question asks for the minimum/maximum value, just read k. If it asks for the x-value that gives the min/max, it is h.', sort_order: 12 },
  { id: 'dc-sat-mathp-0013', deck_id: 'deck-sat-math-patterns', front: 'When you see y = a(x − r₁)(x − r₂), what information is immediately available?', back: 'Pattern: Factored form of a quadratic. The x-intercepts (roots/zeros) are r₁ and r₂. The axis of symmetry is x = (r₁ + r₂)/2, and the vertex x-coordinate is the midpoint of the roots. Example: y = 2(x − 1)(x − 5) has roots at x = 1 and x = 5, axis of symmetry at x = 3. Plug x = 3 back in to find the vertex y-value: y = 2(2)(−2) = −8.', sort_order: 13 },
  { id: 'dc-sat-mathp-0014', deck_id: 'deck-sat-math-patterns', front: 'When you see a function f(x) = (something)/(x − a), how do you find vertical and horizontal asymptotes?', back: 'Pattern: Rational function asymptotes. Vertical asymptote: Set the denominator = 0 (x = a, provided the numerator ≠ 0 there). Horizontal asymptote: Compare degrees of numerator and denominator. Same degree → ratio of leading coefficients. Numerator degree < denominator degree → y = 0. SAT Tip: A hole (not an asymptote) occurs when both numerator and denominator equal zero at the same x-value.', sort_order: 14 },
  { id: 'dc-sat-mathp-0015', deck_id: 'deck-sat-math-patterns', front: 'When you see an exponential growth/decay equation and need to find the rate, what pattern do you use?', back: 'Pattern: Exponential model interpretation. In y = a · bˣ, if b > 1 the growth rate is (b − 1) × 100%. If 0 < b < 1, the decay rate is (1 − b) × 100%. Example: y = 500(1.03)ᵗ means 3% growth per period. y = 1000(0.85)ᵗ means 15% decay per period. SAT Tip: "Doubles every n years" means b = 2 and x = t/n.', sort_order: 15 },
  { id: 'dc-sat-mathp-0016', deck_id: 'deck-sat-math-patterns', front: 'When you see a question about f(g(x)) or composition of functions, what is the approach?', back: 'Pattern: Function composition. Strategy: Work from the inside out. First evaluate g(x), then use that result as the input for f. Example: If f(x) = 2x + 1 and g(x) = x², then f(g(3)) = f(9) = 19. SAT Tip: If asked for f(g(x)) as an expression, replace every x in f with g(x). Be careful with order — f(g(x)) ≠ g(f(x)) in general.', sort_order: 16 },
  { id: 'dc-sat-mathp-0017', deck_id: 'deck-sat-math-patterns', front: 'When you see a system where one equation is linear and one is quadratic, what should you expect?', back: 'Pattern: Linear-quadratic system. This system can have 0, 1, or 2 solutions (where a line intersects a parabola). Strategy: Substitute the linear equation into the quadratic, then solve the resulting quadratic. Use the discriminant to determine how many solutions exist. Example: y = x + 1 and y = x² → x² = x + 1 → x² − x − 1 = 0. Discriminant = 5 > 0, so two intersection points.', sort_order: 17 },
  { id: 'dc-sat-mathp-0018', deck_id: 'deck-sat-math-patterns', front: 'When you see expressions like (a + b)² or (a − b)², what algebraic identity should you apply?', back: 'Pattern: Perfect square trinomials. (a + b)² = a² + 2ab + b² and (a − b)² = a² − 2ab + b². Strategy: If you see x² + 10x + 25, recognize it as (x + 5)². SAT Tip: If you know a² + b² and ab, you can find (a + b)² = a² + 2ab + b². This identity appears frequently in disguised forms.', sort_order: 18 },
  { id: 'dc-sat-mathp-0019', deck_id: 'deck-sat-math-patterns', front: 'When you see x² − y², what factoring pattern should you recognize?', back: 'Pattern: Difference of squares. x² − y² = (x + y)(x − y). Strategy: Any time you see a subtraction between two perfect squares, factor immediately. Example: 49 − 4a² = (7 + 2a)(7 − 2a). SAT Tip: If given x + y = 10 and x − y = 3, then x² − y² = 10 × 3 = 30. No need to solve for x and y individually.', sort_order: 19 },
  { id: 'dc-sat-mathp-0020', deck_id: 'deck-sat-math-patterns', front: 'When you see a question that says "which equivalent form reveals the minimum value," what should you do?', back: 'Pattern: Form-reveals-feature questions. Strategy: Different forms of the same equation reveal different information. Standard form (ax² + bx + c) reveals the y-intercept (c). Vertex form (a(x − h)² + k) reveals the min/max (k). Factored form (a(x − r)(x − s)) reveals the x-intercepts. The SAT specifically asks which form is "most useful" for finding a particular feature.', sort_order: 20 },
  { id: 'dc-sat-mathp-0021', deck_id: 'deck-sat-math-patterns', front: 'When a word problem says "percent of," how do you translate it?', back: 'Pattern: "Percent of" → multiply. Strategy: "X percent of Y" = (X/100) × Y. Example: "30 percent of 50" = 0.30 × 50 = 15. SAT Tip: "What percent of 80 is 20?" translates to (x/100)(80) = 20, so x = 25. Always convert the percent to a decimal or fraction before multiplying.', sort_order: 21 },
  { id: 'dc-sat-mathp-0022', deck_id: 'deck-sat-math-patterns', front: 'When a word problem says "is," "was," "will be," or "yields," how do you translate it?', back: 'Pattern: "Is/was/will be" → equals sign. Strategy: These words indicate equality in equation setup. Example: "Three more than twice a number is 17" → 2x + 3 = 17. SAT Tip: Read the sentence left to right and translate each phrase. "More than" = addition, "less than" = subtraction (in reverse order), "times" = multiplication.', sort_order: 22 },
  { id: 'dc-sat-mathp-0023', deck_id: 'deck-sat-math-patterns', front: 'When you see an age problem, what is the standard setup?', back: 'Pattern: Age problem setup. Strategy: Define the variable as current age. "In 5 years" means add 5, "3 years ago" means subtract 3. Set up the equation based on the relationship described. Example: "Maria is 3 times as old as her son. In 12 years, she will be twice his age." Let son = x now. Maria = 3x now. In 12 years: 3x + 12 = 2(x + 12) → x = 12. Son is 12 now.', sort_order: 23 },
  { id: 'dc-sat-mathp-0024', deck_id: 'deck-sat-math-patterns', front: 'When you see a rate/distance/time problem, what formula and setup should you use?', back: 'Pattern: Distance = Rate × Time (d = rt). Strategy: Organize information in a table with columns for d, r, and t. Key variations: same distance (set d₁ = d₂), combined rates (add rates for working together), round trip (total distance = 2 × one-way). Example: A car travels 60 mph for 2 hours, then 40 mph for 3 hours. Total distance = 120 + 120 = 240 miles.', sort_order: 24 },
  { id: 'dc-sat-mathp-0025', deck_id: 'deck-sat-math-patterns', front: 'When you see a mixture problem (combining solutions, prices, etc.), what is the setup?', back: 'Pattern: Mixture/weighted average. Strategy: Amount₁ × Concentration₁ + Amount₂ × Concentration₂ = Total Amount × Final Concentration. Example: Mix 3 liters of 20% salt solution with x liters of 50% solution to get 30% solution: 0.20(3) + 0.50(x) = 0.30(3 + x) → 0.6 + 0.5x = 0.9 + 0.3x → x = 1.5 liters.', sort_order: 25 },
  { id: 'dc-sat-mathp-0026', deck_id: 'deck-sat-math-patterns', front: 'When you see a word problem about consecutive integers, what expressions should you use?', back: 'Pattern: Consecutive integer expressions. Consecutive integers: n, n+1, n+2. Consecutive even integers: n, n+2, n+4 (where n is even). Consecutive odd integers: n, n+2, n+4 (where n is odd). Example: "The sum of three consecutive integers is 72" → n + (n+1) + (n+2) = 72 → 3n + 3 = 72 → n = 23. The integers are 23, 24, 25.', sort_order: 26 },
  { id: 'dc-sat-mathp-0027', deck_id: 'deck-sat-math-patterns', front: 'When a word problem describes a linear relationship with a flat fee plus a per-unit cost, what model should you use?', back: 'Pattern: Linear cost model. Strategy: Total cost = (per-unit rate)(number of units) + flat fee. This matches y = mx + b, where m is the per-unit rate and b is the initial/flat fee. Example: "A plumber charges $75 for a visit plus $40 per hour" → C = 40h + 75. SAT Tip: The slope is the rate and the y-intercept is the starting value.', sort_order: 27 },
  { id: 'dc-sat-mathp-0028', deck_id: 'deck-sat-math-patterns', front: 'When you see "increased by X%" or "decreased by X%," how do you set up the calculation?', back: 'Pattern: Percent change multiplier. Increase by X%: multiply by (1 + X/100). Decrease by X%: multiply by (1 − X/100). Example: $200 increased by 15% → 200 × 1.15 = $230. A population decreases by 8% per year from 5000: P = 5000(0.92)ᵗ. TRAP: A 20% increase followed by a 20% decrease does NOT return to the original — it gives 0.96 of the original.', sort_order: 28 },
  { id: 'dc-sat-mathp-0029', deck_id: 'deck-sat-math-patterns', front: 'When you see a "work rate" problem (two people or machines working together), what is the strategy?', back: 'Pattern: Combined work rates. Strategy: If A completes a job in a hours and B in b hours, their combined rate is 1/a + 1/b. Time together = 1/(1/a + 1/b) = ab/(a + b). Example: Pipe A fills a tank in 6 hours, Pipe B in 3 hours. Together: 1/6 + 1/3 = 1/6 + 2/6 = 3/6 = 1/2, so they fill it in 2 hours.', sort_order: 29 },
  { id: 'dc-sat-mathp-0030', deck_id: 'deck-sat-math-patterns', front: 'When a word problem involves "per," "for every," or "for each," what operation does this signal?', back: 'Pattern: Unit rate division or multiplication. "Per" typically signals division to find the rate, or multiplication to find the total. Example: "$3.50 per pound for 4 pounds" → 3.50 × 4 = $14.00. "120 miles on 4 gallons" → 120 ÷ 4 = 30 miles per gallon. SAT Tip: Always check units — the answer\'s units tell you whether to multiply or divide.', sort_order: 30 },
  { id: 'dc-sat-mathp-0031', deck_id: 'deck-sat-math-patterns', front: 'When you see a profit/revenue word problem, what formulas should you set up?', back: 'Pattern: Business model equations. Revenue = price × quantity sold. Profit = Revenue − Cost. Break-even occurs when Profit = 0 (Revenue = Cost). Example: A company sells items at $25 each with a $500 fixed cost and $10 per item variable cost. Profit = 25x − (500 + 10x) = 15x − 500. Break-even: 15x = 500, so x = 34 items (round up since you need whole items).', sort_order: 31 },
  { id: 'dc-sat-mathp-0032', deck_id: 'deck-sat-math-patterns', front: 'When a word problem asks about coins, tickets, or items with two different values, how do you set up equations?', back: 'Pattern: Two-variable value problem. Strategy: Set up two equations — one for the total count and one for the total value. Example: "A jar has nickels and dimes. There are 40 coins worth $2.75." Let n = nickels, d = dimes. Equation 1: n + d = 40. Equation 2: 0.05n + 0.10d = 2.75. Solve the system by substitution or elimination.', sort_order: 32 },
  { id: 'dc-sat-mathp-0033', deck_id: 'deck-sat-math-patterns', front: 'When a word problem says "at least," "at most," "no more than," or "no fewer than," what do these translate to?', back: 'Pattern: Inequality keywords. "At least" = ≥, "at most" = ≤, "no more than" = ≤, "no fewer than" = ≥, "more than" = >, "fewer than" = <. Example: "You must buy at least 5 but no more than 12" → 5 ≤ x ≤ 12. SAT Tip: Pay careful attention to whether the boundary value is included (≤/≥) or excluded (</>).', sort_order: 33 },
  { id: 'dc-sat-mathp-0034', deck_id: 'deck-sat-math-patterns', front: 'When you see a proportion or "varies directly" problem, what setup should you use?', back: 'Pattern: Direct variation/proportion. If y varies directly with x, then y = kx (or y₁/x₁ = y₂/x₂). Strategy: Use given values to find k, then use k to find the unknown. Example: "If y = 12 when x = 4, find y when x = 7." k = 12/4 = 3, so y = 3(7) = 21. SAT Tip: "Directly proportional" and "varies directly" mean the same thing.', sort_order: 34 },
  { id: 'dc-sat-mathp-0035', deck_id: 'deck-sat-math-patterns', front: 'When a problem involves "varies inversely" or an inverse relationship, what is the setup?', back: 'Pattern: Inverse variation. If y varies inversely with x, then y = k/x (or xy = k, or x₁y₁ = x₂y₂). Strategy: Find k from given values, then solve. Example: "If y = 6 when x = 8, find y when x = 12." k = 6 × 8 = 48, so y = 48/12 = 4. SAT Tip: In inverse variation, as one variable increases, the other decreases proportionally.', sort_order: 35 },
  { id: 'dc-sat-mathp-0036', deck_id: 'deck-sat-math-patterns', front: 'When you see two triangles that share an angle or have parallel sides, what geometric pattern should you look for?', back: 'Pattern: Similar triangles. Strategy: Look for AA (angle-angle) similarity — if two angles match, the triangles are similar. With parallel lines cutting a transversal, look for corresponding or alternate interior angles. Once similar, set up proportions: corresponding sides are proportional. Example: If triangle sides are 3, 4, 5 and similar triangle has shortest side 6, then sides are 6, 8, 10 (scale factor 2).', sort_order: 36 },
  { id: 'dc-sat-mathp-0037', deck_id: 'deck-sat-math-patterns', front: 'When you see a circle inscribed in a square (or a square inscribed in a circle), what relationships should you use?', back: 'Pattern: Circle-square inscriptions. Circle inscribed in a square: diameter = side length. Area of square = (2r)² = 4r². Shaded area = 4r² − πr². Square inscribed in a circle: diagonal of square = diameter. If side = s, then diagonal = s√2 = 2r, so s = r√2. Example: Circle with r = 5 in a square → square side = 10, shaded area = 100 − 25π.', sort_order: 37 },
  { id: 'dc-sat-mathp-0038', deck_id: 'deck-sat-math-patterns', front: 'When you see an inscribed angle in a circle and a central angle subtending the same arc, what is the relationship?', back: 'Pattern: Inscribed angle theorem. An inscribed angle is half the central angle that subtends the same arc. Also, an inscribed angle that subtends a diameter (semicircle) is always 90°. Strategy: If you see a triangle inscribed in a circle with one side as the diameter, the angle opposite that side is 90°. Example: Central angle = 120° → inscribed angle = 60°.', sort_order: 38 },
  { id: 'dc-sat-mathp-0039', deck_id: 'deck-sat-math-patterns', front: 'When a coordinate geometry problem asks for the distance or midpoint between two points, what formulas apply?', back: 'Pattern: Distance and midpoint formulas. Distance = √((x₂−x₁)² + (y₂−y₁)²). Midpoint = ((x₁+x₂)/2, (y₁+y₂)/2). SAT Tip: If you only need to compare distances (not find exact values), compare the squared distances to avoid the square root. Example: Distance from (1, 2) to (4, 6) = √(9 + 16) = √25 = 5.', sort_order: 39 },
  { id: 'dc-sat-mathp-0040', deck_id: 'deck-sat-math-patterns', front: 'When you see a 3D geometry problem involving a cylinder, cone, or sphere in a word problem context, what is the approach?', back: 'Pattern: 3D volume word problems. Strategy: Identify the shape, extract dimensions from the context, and apply the volume formula. Key formulas: Cylinder V = πr²h, Cone V = (1/3)πr²h, Sphere V = (4/3)πr³. Common SAT twist: "A cylindrical tank holds X gallons" — convert units if needed. "Grain is poured into a cone shape" — identify r and h from the problem.', sort_order: 40 },
  { id: 'dc-sat-mathp-0041', deck_id: 'deck-sat-math-patterns', front: 'When you see a triangle with sides 3-4-5, 5-12-13, or 8-15-17, what should you recognize?', back: 'Pattern: Pythagorean triples. Memorize these common triples: 3-4-5, 5-12-13, 8-15-17, 7-24-25, and their multiples (e.g., 6-8-10, 9-12-15). Strategy: Before using the Pythagorean theorem with messy calculations, check if the triangle is a multiple of a known triple. Example: A right triangle with legs 15 and 20 → divide by 5 to get 3-4, so the hypotenuse is 5 × 5 = 25.', sort_order: 41 },
  { id: 'dc-sat-mathp-0042', deck_id: 'deck-sat-math-patterns', front: 'When you see a 45-45-90 or 30-60-90 triangle in a problem, what side ratios should you use?', back: 'Pattern: Special right triangles. 45-45-90: sides are x, x, x√2. 30-60-90: sides are x, x√3, 2x (opposite the 30°, 60°, and 90° angles respectively). SAT Tip: A square\'s diagonal creates two 45-45-90 triangles. An equilateral triangle\'s altitude creates two 30-60-90 triangles. Example: If the hypotenuse of a 45-45-90 is 10, each leg = 10/√2 = 5√2.', sort_order: 42 },
  { id: 'dc-sat-mathp-0043', deck_id: 'deck-sat-math-patterns', front: 'When a geometry problem gives you a complex figure (multiple shapes combined), what approach should you take?', back: 'Pattern: Composite figure decomposition. Strategy: Break the complex shape into simpler shapes (rectangles, triangles, circles) you know formulas for. For shaded regions, use subtraction: Area of shaded = Area of outer shape − Area of inner shape. Example: A rectangle with a semicircle cut out → A = length × width − (1/2)πr². Always identify which parts to add and which to subtract.', sort_order: 43 },
  { id: 'dc-sat-mathp-0044', deck_id: 'deck-sat-math-patterns', front: 'When a geometry question involves a tangent line to a circle, what key property should you use?', back: 'Pattern: Tangent-radius perpendicularity. A tangent line to a circle is always perpendicular to the radius drawn to the point of tangency. This creates a right angle, often forming a right triangle. Strategy: Draw the radius to the tangent point, mark the 90° angle, and use the Pythagorean theorem. Example: A tangent of length 8 from a point 10 units from the center → radius = √(100 − 64) = 6.', sort_order: 44 },
  { id: 'dc-sat-mathp-0045', deck_id: 'deck-sat-math-patterns', front: 'When you see arc length or sector area questions, what formulas and setup should you use?', back: 'Pattern: Arc and sector formulas. Arc length = (θ/360°) × 2πr. Sector area = (θ/360°) × πr². In radians: Arc length = rθ, Sector area = (1/2)r²θ. Strategy: Find the central angle first, then apply the fraction of the full circle. Example: A 90° sector of a circle with r = 8: arc length = (90/360)(2π)(8) = 4π; sector area = (90/360)(π)(64) = 16π.', sort_order: 45 },
  { id: 'dc-sat-mathp-0046', deck_id: 'deck-sat-math-patterns', front: 'When you see a coordinate geometry question about a circle, what equation form should you recognize?', back: 'Pattern: Circle equation. Standard form: (x − h)² + (y − k)² = r², center (h, k), radius r. If given x² + y² + Dx + Ey + F = 0, complete the square for both x and y to convert to standard form. Example: x² + y² − 6x + 4y − 12 = 0 → (x − 3)² + (y + 2)² = 25, center (3, −2), radius 5. SAT Tip: Watch the signs — (x − 3)² means center x = 3, not −3.', sort_order: 46 },
  { id: 'dc-sat-mathp-0047', deck_id: 'deck-sat-math-patterns', front: 'When you see parallel lines cut by a transversal, what angle relationships should you identify?', back: 'Pattern: Parallel line angle relationships. Corresponding angles are equal. Alternate interior angles are equal. Alternate exterior angles are equal. Co-interior (same-side interior) angles are supplementary (sum to 180°). Strategy: Label one angle, then fill in all others using these rules. SAT Tip: If you know any one angle, you can find all eight angles formed by two parallel lines and a transversal.', sort_order: 47 },
  { id: 'dc-sat-mathp-0048', deck_id: 'deck-sat-math-patterns', front: 'When you see a transformation question (reflection, rotation, translation), what are the key rules?', back: 'Pattern: Coordinate transformations. Reflection over x-axis: (x, y) → (x, −y). Reflection over y-axis: (x, y) → (−x, y). Rotation 90° counterclockwise: (x, y) → (−y, x). Rotation 180°: (x, y) → (−x, −y). Translation: (x, y) → (x + a, y + b). SAT Tip: For reflections over the line y = x, swap coordinates: (x, y) → (y, x).', sort_order: 48 },
  { id: 'dc-sat-mathp-0049', deck_id: 'deck-sat-math-patterns', front: 'When a problem involves similar figures and asks about area or volume, how does the scale factor apply?', back: 'Pattern: Scale factor and dimension relationships. If the linear scale factor is k, then areas scale by k² and volumes scale by k³. Example: If two similar cylinders have heights in ratio 2:3, their surface areas are in ratio 4:9 and volumes in ratio 8:27. SAT Tip: A common trap is applying the linear ratio directly to area or volume — always square it for area and cube it for volume.', sort_order: 49 },
  { id: 'dc-sat-mathp-0050', deck_id: 'deck-sat-math-patterns', front: 'When you see the equation of a line passing through two given points, what is the fastest method?', back: 'Pattern: Line through two points. Strategy: Find slope m = (y₂ − y₁)/(x₂ − x₁), then use point-slope form y − y₁ = m(x − x₁). Convert to whatever form the answer choices use. Shortcut: If the answer choices are in slope-intercept form, just find m and then b = y₁ − mx₁. Example: Through (2, 3) and (5, 9): m = 6/3 = 2, so y − 3 = 2(x − 2) → y = 2x − 1.', sort_order: 50 },
  { id: 'dc-sat-mathp-0051', deck_id: 'deck-sat-math-patterns', front: 'When a scatterplot is shown and you are asked about the relationship, what should you look for?', back: 'Pattern: Scatterplot analysis. Strategy: Look at the overall trend (positive, negative, or no association), the form (linear, quadratic, exponential), and the strength (how closely points follow the pattern). If asked about an outlier, find the point farthest from the trend. SAT Tip: "Positive association" means as x increases, y tends to increase. A curved pattern means a non-linear model may fit better.', sort_order: 51 },
  { id: 'dc-sat-mathp-0052', deck_id: 'deck-sat-math-patterns', front: 'When you are given a line of best fit equation and asked to interpret the slope or y-intercept, what does the SAT expect?', back: 'Pattern: Line of best fit interpretation. The slope represents the predicted change in y for each one-unit increase in x. The y-intercept represents the predicted value of y when x = 0. SAT Tip: Use context-specific language. Example: If y = 2.5x + 10 models test scores vs. study hours, say "each additional hour of studying is associated with a 2.5-point increase in score." Use "predicted" or "estimated" — it is a model, not exact.', sort_order: 52 },
  { id: 'dc-sat-mathp-0053', deck_id: 'deck-sat-math-patterns', front: 'When you see a residual or are asked "which point has the greatest residual," what do you calculate?', back: 'Pattern: Residual analysis. Residual = actual value − predicted value. A positive residual means the actual value is above the line of best fit; negative means below. The point with the greatest residual is the one farthest vertically from the line. Strategy: For each point in question, calculate |actual y − predicted y| and pick the largest. SAT Tip: Residual plots should show random scatter if the model is a good fit.', sort_order: 53 },
  { id: 'dc-sat-mathp-0054', deck_id: 'deck-sat-math-patterns', front: 'When you see a two-way frequency table, what types of questions should you expect?', back: 'Pattern: Two-way table analysis. Common questions: (1) Find a conditional probability — restrict to one row or column, then divide. (2) Find a marginal probability — use the totals row/column. (3) Compare proportions across groups. Strategy: Always identify whether the question asks about the whole table, a row total, or a column total before calculating. Example: P(A|B) = count of (A and B) / count of B.', sort_order: 54 },
  { id: 'dc-sat-mathp-0055', deck_id: 'deck-sat-math-patterns', front: 'When a question asks about relative frequency from a two-way table, how is it different from frequency?', back: 'Pattern: Relative frequency vs. frequency. Frequency = raw count. Relative frequency = count divided by the appropriate total (expressed as a fraction, decimal, or percent). Joint relative frequency uses the grand total. Marginal relative frequency uses the grand total. Conditional relative frequency uses a row or column total. SAT Tip: Read carefully whether they ask for "proportion of all students" (grand total) or "proportion of males" (row/column total).', sort_order: 55 },
  { id: 'dc-sat-mathp-0056', deck_id: 'deck-sat-math-patterns', front: 'When a question asks you to compare the mean and median, what pattern should you recognize?', back: 'Pattern: Mean vs. median in skewed distributions. In a right-skewed distribution (tail to the right), mean > median. In a left-skewed distribution (tail to the left), mean < median. In a symmetric distribution, mean ≈ median. Strategy: Outliers pull the mean toward them but do not affect the median. SAT Tip: If asked which measure is "more appropriate" for a skewed dataset, the answer is usually the median because it resists outliers.', sort_order: 56 },
  { id: 'dc-sat-mathp-0057', deck_id: 'deck-sat-math-patterns', front: 'When a data point is added or removed from a dataset and you are asked how it affects the mean, what should you consider?', back: 'Pattern: Mean manipulation. Adding a value above the current mean increases the mean; adding a value below decreases it. Removing a value above the mean decreases the mean; removing a value below increases it. Strategy: New mean = (old sum ± new value) / (new count). SAT Tip: You don\'t always need to recalculate — just determine whether the added/removed value is above or below the current mean.', sort_order: 57 },
  { id: 'dc-sat-mathp-0058', deck_id: 'deck-sat-math-patterns', front: 'When a question provides a histogram or dot plot and asks about the median, how do you find it?', back: 'Pattern: Finding median from a visual display. Strategy: Count the total number of data points (n). The median is the (n+1)/2 th value when n is odd, or the average of the n/2 th and (n/2 + 1)th values when n is even. Count from left to right through the bars/dots until you reach that position. Example: For 25 data points, the median is the 13th value. Count through each bar until you pass the 13th value.', sort_order: 58 },
  { id: 'dc-sat-mathp-0059', deck_id: 'deck-sat-math-patterns', front: 'When you see "percent increase" or "percent decrease," what formula should you use and what trap should you avoid?', back: 'Pattern: Percent change formula. Percent change = ((new − old) / old) × 100%. TRAP: The denominator is always the ORIGINAL value, not the new value. Example: Price goes from $80 to $100 → percent increase = (20/80) × 100% = 25%. But from $100 to $80 is (20/100) × 100% = 20% decrease. A 25% increase is NOT reversed by a 25% decrease.', sort_order: 59 },
  { id: 'dc-sat-mathp-0060', deck_id: 'deck-sat-math-patterns', front: 'When a survey or study question asks about bias, random sampling, or generalization, what should you evaluate?', back: 'Pattern: Statistical study evaluation. Key questions: (1) Was the sample randomly selected? If not, results may be biased. (2) Can you generalize to the whole population? Only if the sample is representative. (3) Can you establish causation? Only in a controlled experiment with random assignment, not observational studies. SAT Tip: "A random sample of students at School X" → results apply to School X only, not all students everywhere.', sort_order: 60 },
  { id: 'dc-sat-mathp-0061', deck_id: 'deck-sat-math-patterns', front: 'When you see a confidence interval or margin of error question, what should you know?', back: 'Pattern: Margin of error interpretation. A larger sample size → smaller margin of error → more precise estimate. The confidence interval is the estimate ± margin of error. "95% confident that the true proportion is between 42% and 48%" means the margin of error is 3%. SAT Tip: The SAT will not ask you to calculate a margin of error, only to interpret or compare them. Doubling the sample size does not halve the margin of error — it reduces it by a factor of √2.', sort_order: 61 },
  { id: 'dc-sat-mathp-0062', deck_id: 'deck-sat-math-patterns', front: 'When a box plot is shown and you need to compare two datasets, what features do you compare?', back: 'Pattern: Box plot comparison. Compare: median (middle line), IQR (box width = Q3 − Q1), range (whisker to whisker), and symmetry/skew. The box contains the middle 50% of data. SAT Tip: A wider box means more variability in the middle 50%. If the median line is not centered in the box, the data is skewed. The SAT often asks which dataset has a greater range, IQR, or median.', sort_order: 62 },
  { id: 'dc-sat-mathp-0063', deck_id: 'deck-sat-math-patterns', front: 'When a problem involves standard deviation conceptually (without calculation), what should you know?', back: 'Pattern: Standard deviation interpretation. Standard deviation measures spread — how far data points typically are from the mean. A larger SD means more spread out. If all values are the same, SD = 0. Adding or subtracting a constant to all values does not change SD. Multiplying all values by k multiplies SD by |k|. SAT Tip: The SAT never asks you to calculate SD, only to compare or interpret it conceptually.', sort_order: 63 },
  { id: 'dc-sat-mathp-0064', deck_id: 'deck-sat-math-patterns', front: 'When a table provides data and asks about probability, how do you determine if it is conditional or unconditional?', back: 'Pattern: Conditional vs. unconditional probability. Unconditional: P(A) = favorable outcomes / total outcomes. Conditional: P(A|B) = P(A and B) / P(B) — restrict your universe to B first, then find A within it. SAT Tip: The phrase "given that" or "among those who" signals a conditional probability. Use the row or column total for B as your denominator, not the grand total.', sort_order: 64 },
  { id: 'dc-sat-mathp-0065', deck_id: 'deck-sat-math-patterns', front: 'When a problem involves probability with "or," how do you handle it?', back: 'Pattern: Addition rule for probability. P(A or B) = P(A) + P(B) − P(A and B). If A and B are mutually exclusive (cannot happen together), then P(A and B) = 0, so P(A or B) = P(A) + P(B). SAT Tip: "Or" on the SAT is inclusive or (includes both). Always subtract the overlap unless the events cannot co-occur. Example: P(red or face card) from a deck = 26/52 + 12/52 − 6/52 = 32/52.', sort_order: 65 },
  { id: 'dc-sat-mathp-0066', deck_id: 'deck-sat-math-patterns', front: 'When you see even + even, odd + odd, or even × odd, what should you know about the result?', back: 'Pattern: Even/odd arithmetic rules. Even ± even = even. Odd ± odd = even. Even ± odd = odd. Even × anything = even. Odd × odd = odd. Strategy: Use these rules to determine if an expression must be even or odd without computing. Example: If n is odd, then n² is odd, and n² + 1 is even. SAT Tip: Test with small numbers (like 2 for even, 3 for odd) to verify if unsure.', sort_order: 66 },
  { id: 'dc-sat-mathp-0067', deck_id: 'deck-sat-math-patterns', front: 'When multiplying or dividing positive and negative numbers, how do you quickly determine the sign?', back: 'Pattern: Sign rules for multiplication/division. Positive × Positive = Positive. Negative × Negative = Positive. Positive × Negative = Negative. Count the number of negative factors: even count → positive result, odd count → negative result. Example: (−2)(−3)(−4) has 3 negatives (odd), so the product is negative: −24. SAT Tip: This extends to exponents: (−x)⁴ > 0 but (−x)³ < 0 when x > 0.', sort_order: 67 },
  { id: 'dc-sat-mathp-0068', deck_id: 'deck-sat-math-patterns', front: 'When a problem involves remainders (e.g., "when n is divided by 5, the remainder is 3"), how do you work with this?', back: 'Pattern: Remainder arithmetic. "n divided by 5 has remainder 3" means n = 5q + 3 for some integer q. Possible values: 3, 8, 13, 18, 23... Strategy: Write n in the form n = divisor × quotient + remainder. To find the remainder of a sum: add the individual remainders, then take the remainder of that sum. Example: If a has remainder 3 and b has remainder 4 when divided by 7, then a + b has remainder 0 (since 3 + 4 = 7) when divided by 7.', sort_order: 68 },
  { id: 'dc-sat-mathp-0069', deck_id: 'deck-sat-math-patterns', front: 'When you need to check divisibility quickly, what are the key rules?', back: 'Pattern: Divisibility shortcuts. By 2: last digit is even. By 3: sum of digits divisible by 3. By 4: last two digits form a number divisible by 4. By 5: last digit is 0 or 5. By 6: divisible by both 2 and 3. By 9: sum of digits divisible by 9. By 10: last digit is 0. Example: Is 738 divisible by 3? Sum of digits: 7 + 3 + 8 = 18, and 18 is divisible by 3, so yes.', sort_order: 69 },
  { id: 'dc-sat-mathp-0070', deck_id: 'deck-sat-math-patterns', front: 'When a problem asks about the number of factors or involves prime factorization, what is the strategy?', back: 'Pattern: Prime factorization approach. Strategy: Break the number into prime factors. To find the total number of factors, add 1 to each exponent and multiply. Example: 72 = 2³ × 3² → number of factors = (3+1)(2+1) = 12. SAT Tip: To find the GCF, take the minimum exponent of each shared prime. For LCM, take the maximum exponent of each prime. GCF(12,18) = 2¹ × 3¹ = 6. LCM(12,18) = 2² × 3² = 36.', sort_order: 70 },
  { id: 'dc-sat-mathp-0071', deck_id: 'deck-sat-math-patterns', front: 'When a problem involves a units digit pattern (e.g., "what is the units digit of 7⁵³?"), what is the approach?', back: 'Pattern: Cyclical units digits. The units digit of powers follows a repeating cycle. Strategy: Find the cycle length, then use the remainder when dividing the exponent by the cycle length. Powers of 7: 7, 9, 3, 1, 7, 9, 3, 1... (cycle of 4). For 7⁵³: 53 ÷ 4 = 13 remainder 1. The 1st digit in the cycle is 7, so the units digit of 7⁵³ is 7. Common cycles: 2→2,4,8,6; 3→3,9,7,1; 4→4,6; 5→5; 6→6.', sort_order: 71 },
  { id: 'dc-sat-mathp-0072', deck_id: 'deck-sat-math-patterns', front: 'When you see a question asking if a number is prime, what quick checks should you perform?', back: 'Pattern: Primality testing shortcut. Strategy: Check divisibility by primes up to the square root of the number. For numbers up to 100, test 2, 3, 5, and 7 only. If none divide evenly, the number is prime. Example: Is 97 prime? √97 ≈ 9.8, so test 2, 3, 5, 7. 97 is odd, not divisible by 3 (9+7=16), doesn\'t end in 0/5, and 97/7 ≈ 13.9. So 97 is prime.', sort_order: 72 },
  { id: 'dc-sat-mathp-0073', deck_id: 'deck-sat-math-patterns', front: 'When you see an expression like 2⁻³ or x⁻ⁿ, what should you recognize about negative exponents?', back: 'Pattern: Negative exponent rules. x⁻ⁿ = 1/xⁿ and 1/x⁻ⁿ = xⁿ. A negative exponent means "take the reciprocal." (a/b)⁻ⁿ = (b/a)ⁿ. Example: 2⁻³ = 1/2³ = 1/8. (3/4)⁻² = (4/3)² = 16/9. SAT Tip: When simplifying complex exponent expressions, convert all negative exponents to fractions first to avoid sign errors.', sort_order: 73 },
  { id: 'dc-sat-mathp-0074', deck_id: 'deck-sat-math-patterns', front: 'When you see fractional exponents like x^(2/3), how do you interpret them?', back: 'Pattern: Fractional exponent conversion. x^(a/b) = ᵇ√(xᵃ) = (ᵇ√x)ᵃ. The denominator is the root, the numerator is the power. Example: 8^(2/3) = (³√8)² = 2² = 4. 27^(4/3) = (³√27)⁴ = 3⁴ = 81. SAT Tip: It is usually easier to take the root first, then raise to the power, to keep numbers small. x^(1/2) = √x, x^(1/3) = ³√x.', sort_order: 74 },
  { id: 'dc-sat-mathp-0075', deck_id: 'deck-sat-math-patterns', front: 'When you see an expression with multiple variables and exponents like (2x³y²)⁴, how do you simplify?', back: 'Pattern: Power of a product. Distribute the exponent to every factor inside: (2x³y²)⁴ = 2⁴ · x¹² · y⁸ = 16x¹²y⁸. Rules: (ab)ⁿ = aⁿbⁿ, (aᵐ)ⁿ = aᵐⁿ. SAT Tip: The most common mistake is forgetting to raise the coefficient to the power. Always apply the outer exponent to the numerical coefficient as well.', sort_order: 75 },
  { id: 'dc-sat-mathp-0076', deck_id: 'deck-sat-math-patterns', front: 'When should you plug in numbers instead of solving algebraically?', back: 'Pattern: Plug-in strategy trigger. Use plugging in when: (1) The question has variables in the answer choices, (2) the question says "must be true for all values," (3) you are stuck on an algebraic approach, or (4) the question involves percents or fractions without specific values. Strategy: Choose simple, legal values for the variables, compute the answer, then test which answer choice matches. Avoid 0 and 1 as they have special properties.', sort_order: 76 },
  { id: 'dc-sat-mathp-0077', deck_id: 'deck-sat-math-patterns', front: 'When plugging in numbers, what are the best "smart numbers" to choose?', back: 'Pattern: Smart number selection. For percents: use 100. For fractions: use the LCD (e.g., if fractions have denominators 3 and 4, use 12). For "any integer": use 2, 3, or 5 (small primes). For even/odd: use 2 for even and 3 for odd. Avoid 0 and 1 (too many special properties). Avoid numbers that appear in the problem. Example: "What is 30% of x% of 200?" — let x = 50 for easy calculation.', sort_order: 77 },
  { id: 'dc-sat-mathp-0078', deck_id: 'deck-sat-math-patterns', front: 'When should you backsolve (plug in answer choices)?', back: 'Pattern: Backsolving strategy. Use when: (1) Answer choices are simple numbers, (2) the question asks for a specific value ("what is x?"), (3) setting up the equation seems complicated. Strategy: Start with choice B or C (the middle value if choices are ordered). If the result is too large, try a smaller choice; if too small, try larger. Example: "If 3x + 7 = 22, what is x?" — Test C: 5 → 3(5)+7 = 22. Correct!', sort_order: 78 },
  { id: 'dc-sat-mathp-0079', deck_id: 'deck-sat-math-patterns', front: 'When testing boundary values or extreme cases, what patterns should you check?', back: 'Pattern: Boundary testing. Strategy: Test x = 0, negative values, fractions between 0 and 1, and very large numbers to check if a statement is always true. This is especially useful for "must be true" or "could be true" questions. Example: "If x² > x, which values of x work?" Test x = 2 (yes), x = 0.5 (no, 0.25 < 0.5), x = −1 (yes, 1 > −1). So it works for x > 1 or x < 0, not for 0 < x < 1.', sort_order: 79 },
  { id: 'dc-sat-mathp-0080', deck_id: 'deck-sat-math-patterns', front: 'When a question says "must be true" vs. "could be true," how does your approach differ?', back: 'Pattern: Must be true vs. could be true. "Must be true": You need to prove it works for ALL valid cases — or find ONE counterexample to eliminate it. "Could be true": You only need ONE example that works to confirm it. Strategy: For "must be true," try to disprove each choice with a counterexample. For "could be true," try to find one valid example for each choice. Eliminate choices that can NEVER be true.', sort_order: 80 },
  { id: 'dc-sat-mathp-0081', deck_id: 'deck-sat-math-patterns', front: 'When you see a "which of the following is equivalent" question with algebraic expressions, what is the plug-in approach?', back: 'Pattern: Equivalence testing by substitution. Strategy: Pick a value for the variable, evaluate the original expression, then evaluate each answer choice with the same value. The correct answer must give the same result. Use a non-obvious value (not 0 or 1). If two choices give the same result, test a second value to break the tie. Example: To test if (x²−1)/(x−1) = x+1, plug in x = 3: (9−1)/2 = 4, and 3+1 = 4. They match.', sort_order: 81 },
  { id: 'dc-sat-mathp-0082', deck_id: 'deck-sat-math-patterns', front: 'When plugging in for a percent problem, why is 100 the ideal starting number?', back: 'Pattern: Percent problems with 100. Since percent literally means "per 100," starting with 100 makes every percentage a simple whole number. Example: "A price increases by 20% then decreases by 15%. What is the net change?" Start at 100 → 120 → 120 × 0.85 = 102. Net change = 2% increase. This avoids fraction/decimal arithmetic entirely.', sort_order: 82 },
  { id: 'dc-sat-mathp-0083', deck_id: 'deck-sat-math-patterns', front: 'When a system of equations has ugly coefficients and you do not see a clean algebraic path, what should you try?', back: 'Pattern: Plugging in from answer choices for systems. Strategy: If the answer gives specific (x, y) pairs or a specific value, substitute each choice into both equations and check which one satisfies both. This avoids messy elimination or substitution. Example: "Which ordered pair satisfies 2.5x − 3.7y = 12.1 and 1.3x + 4.2y = 8.9?" Test each choice — the correct one makes both equations true.', sort_order: 83 },
  { id: 'dc-sat-mathp-0084', deck_id: 'deck-sat-math-patterns', front: 'When a geometry question gives you a variable angle or side, when should you plug in a specific value?', back: 'Pattern: Plugging in for geometry variables. Strategy: If a geometry question uses variables and asks for a general relationship, pick specific angle measures or side lengths that satisfy the constraints. Example: "In a triangle with angles x°, 2x°, and 3x°, find 3x." Since angles sum to 180°: x + 2x + 3x = 180, so x = 30 and 3x = 90. You can also verify by plugging x = 30 into each answer choice.', sort_order: 84 },
  { id: 'dc-sat-mathp-0085', deck_id: 'deck-sat-math-patterns', front: 'When a "plug in" attempt gives two answer choices the same value, what should you do?', back: 'Pattern: Resolving plug-in ties. Strategy: Plug in a different number and re-evaluate only the tied choices. Pick a number with different properties (e.g., if you used an even number, try odd; if you used positive, try negative if allowed). Example: With x = 2, both choice A and C give 6. Try x = 3: choice A gives 10, choice C gives 9. Since the original expression gives 10 with x = 3, A is correct.', sort_order: 85 },
  { id: 'dc-sat-mathp-0086', deck_id: 'deck-sat-math-patterns', front: 'On the no-calculator section, how do you quickly multiply two-digit numbers mentally?', back: 'Pattern: Mental multiplication shortcuts. Use the distributive property: 23 × 17 = 23 × (20 − 3) = 460 − 69 = 391. Or: 23 × 17 = (20 + 3)(17) = 340 + 51 = 391. For numbers near 100: 97 × 95 = (100 − 3)(100 − 5) = 10000 − 800 + 15 = 9215. SAT Tip: Look for ways to decompose numbers into easier factors. 48 × 25 = 48 × (100/4) = 4800/4 = 1200.', sort_order: 86 },
  { id: 'dc-sat-mathp-0087', deck_id: 'deck-sat-math-patterns', front: 'On the no-calculator section, how do you handle decimal and fraction conversions quickly?', back: 'Pattern: Key fraction-decimal equivalents. Memorize: 1/8 = 0.125, 1/6 ≈ 0.167, 1/5 = 0.2, 1/4 = 0.25, 1/3 ≈ 0.333, 3/8 = 0.375, 2/5 = 0.4, 5/8 = 0.625, 2/3 ≈ 0.667, 3/4 = 0.75, 7/8 = 0.875. Strategy: Convert decimals to fractions for exact arithmetic on the no-calculator section. Example: 0.375 × 16 = (3/8)(16) = 6 is much easier than long multiplication.', sort_order: 87 },
  { id: 'dc-sat-mathp-0088', deck_id: 'deck-sat-math-patterns', front: 'On the no-calculator section, what approach works best for simplifying complex fractions?', back: 'Pattern: Complex fraction simplification. Strategy: Multiply the numerator and denominator by the LCD of all the small fractions. Example: (1/2 + 1/3) / (1/4 − 1/6). LCD of 2, 3, 4, 6 is 12. Multiply top and bottom by 12: (6 + 4)/(3 − 2) = 10/1 = 10. This eliminates all fractions in one step and avoids the error-prone "flip and multiply" chain.', sort_order: 88 },
  { id: 'dc-sat-mathp-0089', deck_id: 'deck-sat-math-patterns', front: 'On the no-calculator section, how do you quickly estimate square roots?', back: 'Pattern: Square root estimation. Know perfect squares: 1, 4, 9, 16, 25, 36, 49, 64, 81, 100, 121, 144, 169, 196, 225. For non-perfect squares, find the two nearest perfect squares and interpolate. Example: √50 is between √49 = 7 and √64 = 8, closer to 7. Estimate ≈ 7.07. SAT Tip: √2 ≈ 1.414, √3 ≈ 1.732, √5 ≈ 2.236 are worth memorizing for the no-calculator section.', sort_order: 89 },
  { id: 'dc-sat-mathp-0090', deck_id: 'deck-sat-math-patterns', front: 'On the calculator section, when should you still solve by hand instead of using the calculator?', back: 'Pattern: Calculator vs. algebra decision. Use algebra (not calculator) when: (1) The problem involves variables/symbols, (2) you need an exact answer with radicals or π, (3) the algebraic approach is faster (like factoring x² − 9 = 0). Use the calculator when: (1) Numbers are large or messy, (2) you need a decimal approximation, (3) you want to verify an algebraic answer. SAT Tip: Graphing on a calculator can visually solve systems of equations or find zeros.', sort_order: 90 },
  { id: 'dc-sat-mathp-0091', deck_id: 'deck-sat-math-patterns', front: 'When a grid-in question asks for a fraction answer, what formats are acceptable?', back: 'Pattern: Grid-in fraction format. You can grid fractions using the slash: 7/12 is entered as 7/12. You do NOT need to reduce fractions — 2/4 and 1/2 are both accepted. You CANNOT grid mixed numbers — convert 3 1/2 to 7/2 or 3.5. TRAP: If you grid 3 1/2, it will be read as 31/2. Negative answers cannot be gridded — if you get a negative, recheck your work. The maximum gridded value is 9999.', sort_order: 91 },
  { id: 'dc-sat-mathp-0092', deck_id: 'deck-sat-math-patterns', front: 'When a grid-in question asks for a decimal answer, what should you know about formatting?', back: 'Pattern: Grid-in decimal format. You have 4 columns to grid in. Start from the left — do not leave leading blank spaces. For decimals: 0.5 can be gridded as .5 (no need for the leading zero) or 0.5. For repeating decimals, truncate or round to fill the grid: 1/3 = .333. TRAP: Do NOT round .333 to .3 — use as many digits as the grid allows. Grid .333 not .3 for maximum accuracy.', sort_order: 92 },
  { id: 'dc-sat-mathp-0093', deck_id: 'deck-sat-math-patterns', front: 'When a grid-in has multiple possible correct answers, which one should you enter?', back: 'Pattern: Multiple valid grid-in answers. Some questions have multiple valid answers (e.g., "What is one possible value of x?"). Any valid answer will be accepted. Strategy: Choose the simplest answer that is easiest to grid. Example: If x can be any number between 3 and 7, grid 4 or 5 (whole numbers are easiest). If the answer is a range, pick a value clearly within the range, not at the boundary.', sort_order: 93 },
  { id: 'dc-sat-mathp-0094', deck_id: 'deck-sat-math-patterns', front: 'When a grid-in asks "what is the value of x" and you get a fraction like 11/7, should you convert to a decimal?', back: 'Pattern: Grid-in — fraction vs. decimal decision. If the fraction fits in 4 columns (like 11/7 uses 4 spaces), grid the fraction. If it does not fit (like 113/97), convert to a decimal and truncate/round to fit. Example: 11/7 → grid as 11/7 (4 characters). 1.571428... → grid as 1.57 (4 characters). Either form is accepted if it fits the grid. SAT Tip: Fractions avoid rounding errors, so prefer them when they fit.', sort_order: 94 },
  { id: 'dc-sat-mathp-0095', deck_id: 'deck-sat-math-patterns', front: 'What are the most common grid-in traps the SAT uses?', back: 'Pattern: Common grid-in traps. (1) The question asks for 2x, not x — always re-read what is being asked. (2) Mixed numbers: convert to improper fractions. (3) Negative answers cannot be gridded — if you get one, your work is likely wrong. (4) Percent: if asked for "the percent," grid 25 not 0.25. (5) Units: the answer might need conversion (feet to inches, etc.). (6) "What is one possible value" — make sure your value satisfies ALL given conditions.', sort_order: 95 },
  { id: 'dc-sat-mathp-0096', deck_id: 'deck-sat-math-patterns', front: 'When a grid-in involves a system of equations, what should you watch for?', back: 'Pattern: Grid-in system traps. The question may ask for x + y, not x or y individually. Or it may ask for the value of an expression like 3a − b. Strategy: See if you can manipulate the equations to produce the requested expression directly without solving for individual variables. Example: If 2x + y = 10 and x + y = 7, subtraction gives x = 3. If asked for y, then y = 4. If asked for xy, calculate 3 × 4 = 12.', sort_order: 96 },
  { id: 'dc-sat-mathp-0097', deck_id: 'deck-sat-math-patterns', front: 'When a grid-in asks for a ratio or proportion answer, how should you format it?', back: 'Pattern: Grid-in ratio answers. Ratios should be gridded as fractions or decimals, NOT with a colon. "The ratio of a to b" where a = 3 and b = 5 should be gridded as 3/5 or .6, never 3:5 (colon is not available on the grid). If asked for "the value of a/b" it is the same — grid 3/5 or .6. SAT Tip: If the ratio simplifies nicely to a decimal, that may be easier to grid.', sort_order: 97 },
  { id: 'dc-sat-mathp-0098', deck_id: 'deck-sat-math-patterns', front: 'When a grid-in answer involves π, what should you do?', back: 'Pattern: Grid-in with π. You cannot grid the π symbol, so the question will be designed so that π cancels out or the answer is a numerical value without π. If your answer still contains π, you likely need to simplify further or recheck. Example: "What is the ratio of the area of a circle with radius 3 to the area of a circle with radius 6?" = 9π/36π = 1/4. Grid 1/4 or .25.', sort_order: 98 },
  { id: 'dc-sat-mathp-0099', deck_id: 'deck-sat-math-patterns', front: 'When a grid-in asks for a percent and you calculate 0.35, should you grid 0.35 or 35?', back: 'Pattern: Percent vs. decimal in grid-ins. Read the question carefully. If it says "what percent," grid 35 (the number without the % sign). If it says "what is the probability" or "what fraction," grid .35 or 7/20. TRAP: Mixing these up is one of the most common grid-in errors. Example: "What percent of 80 is 28?" → 28/80 = 0.35 = 35%. Grid 35. But "What is the probability?" → grid .35.', sort_order: 99 },
  { id: 'dc-sat-mathp-0100', deck_id: 'deck-sat-math-patterns', front: 'When a grid-in answer is a dollar amount or unit measurement, do you include the unit?', back: 'Pattern: Grid-in units. Never grid dollar signs, unit labels, or symbols — only the number. The grid only accepts digits, a decimal point, and a fraction slash. If the answer is $4.50, grid 4.5 or 4.50 or 9/2. If the answer is 12 inches, grid 12. SAT Tip: Make sure you have converted to the correct unit before gridding. If the question asks for feet but you calculated inches, divide by 12 before gridding.', sort_order: 100 },
];
